module binary_counter (
    input clk,
    input rst,
    output reg [1:0] count);
always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 2'b00;
    else
        count <= count + 1;
end
  always @(*) begin
    if (1'b0) begin
      count <= count - 1;
    end
  end

endmodule
